---
import type { HTMLAttributes } from "astro/types"

type Props = Omit<HTMLAttributes<"svg">, "name" | "href"> & {
  href?: HTMLAttributes<"a">["href"]
  name?: string | number | null
}

const { name, href, ...props } = Astro.props

const hrefMap = {
  "x.com": "x",
  twitter: "twitter",
  facebook: "facebook",
  instagram: "instagram",
  pinterest: "pinterest",
  youtube: "youtube",
  tiktok: "tiktok",
  snapchat: "snapchat",
  reddit: "reddit",
  tumblr: "tumblr",
  "wa.me": "whatsapp",
  telegram: "telegram",
  discord: "discord",
  vimeo: "vimeo",
  flickr: "flickr",
  yelp: "yelp",
  spotify: "spotify",
  behance: "behance",
  dribbble: "dribbble",
  soundcloud: "soundcloud",
  github: "github",
  twitch: "twitch",
  "tel:": "phone",
  "mailto:": "mail",
  "maps.app.goo.gl": "map-pin",
  linkedin: "linkedin",
} as const

const icons = import.meta.glob(
  [
    "/node_modules/lucide-static/icons/*.svg",
    "/node_modules/simple-icons/icons/*.svg",
  ],
  { eager: true }
) as Record<string, { default: any }>

const foundPath = () => {
  let foundPath: string | undefined = undefined

  // For x.com, use the Simple Icons X instead of Lucide's X icon.
  if (name === "x.com") {
    foundPath = "/node_modules/simple-icons/icons/x.svg"
  } else if (name) {
    foundPath = Object.keys(icons).find((key) => key.includes(`/${name}.svg`))
  } else if (href) {
    const hrefKey = Object.keys(hrefMap).find((key) =>
      href.toString().includes(key)
    )
    const hrefValue = hrefMap[hrefKey as keyof typeof hrefMap]
    foundPath = Object.keys(icons)
      .reverse()
      .find((key) => key.includes(`/${hrefValue}.svg`))
  }

  return foundPath
}

const iconPath = foundPath()
const module = iconPath ? icons[iconPath] : undefined
const Comp = module?.default
---

{
  Comp && foundPath()?.includes("simple-icons") && (
    <Comp
      height={24}
      width={24}
      fill="currentColor"
      class="size-[1em] text-base"
      {...props}
    />
  )
}

{
  Comp && foundPath()?.includes("lucide-static") && (
    <Comp
      height={24}
      width={24}
      fill="none"
      class="size-[1em] text-base"
      {...props}
    />
  )
}
